#include <stdio.h>

int classify(int n) {
    if (n < 0) {
        return -1;    // early exit
    }

    int sum = 0;
    int i = 1;
    while (i <= n) {  // loop: creates back edge
        sum += i;
        i++;
    }

    if (sum > 100) {  // branch: creates diamond
        printf("large: %d\n", sum);
    } else {
        printf("small: %d\n", sum);
    }
    return sum;
}

#include <stdlib.h>

struct Point { int x; int y; };

int add(int a, int b) { return a + b; }
int mul(int a, int b) { return a * b; }

int main() {
    struct Point *p = (struct Point *)malloc(sizeof(struct Point));
    p->x = 10;
    p->y = 20;
    struct Point *q = p;
    int val = add(q->x, q->y);
    int result = mul(val, 2);
    free(p);
    return result;
}

